// ── ProjectCard ────────────────────────────────────────────────────────────────

function ProjectCard({
  contact,
  rooms,
  platformUsers,
  canAssign,
  canEdit,
  workflow,
  qb,
  urgency,
  lastAttempt,
  openTaskCount,
  cardActionHandlerFor,
  resolveActionLabel,
  draftVisitId,
  statusMap,
  onOpenFitterPicker,
  onNavigate,
  onOpenInvoice,
  onOpenEdit,
}: {
  contact: ProjectContact;
  rooms: RoomWithIdx[];
  platformUsers: ProjectPlatformUser[];
  canAssign: boolean;
  canEdit: boolean;
  workflow: ProjectWorkflowDef | undefined;
  qb?: QBState;
  urgency: Urgency;
  lastAttempt?: { at: string; by: string | null; count: number; method: string | null; methodCounts?: Record<string, number> | null } | null;
  openTaskCount?: number;
  cardActionHandlerFor: (
    stageKey: string,
    leadStatusKey: string | undefined,
  ) => CardActionHandlerData | null;
  resolveActionLabel: (
    stageKey: string,
    leadStatusKey: string | undefined,
    substageId: string | undefined,
  ) => string;
  draftVisitId?: number | string | null;
  statusMap: Map<string, { stage?: string | null }>;
  onOpenFitterPicker: (contactId: string, roomIdx: number) => void;
  onNavigate: (contactId: string, roomIdx: number) => void;
  onOpenInvoice: (firstId: string, allIds: string[]) => void;
  onOpenEdit: (contactId: string) => void;
}) {
  const name = getContactName(contact);
  const earliestInstall =
    rooms.map((r) => r.installStart).filter(Boolean).sort()[0] ?? null;
  const installLabel = fmtInstallDate(earliestInstall);

  // ── Action strip state ─────────────────────────────────────────────────────
  const now = useNowTick();
  const [dispatchingAction, setDispatchingAction] = useState(false);

  // Pick the primary stage from the first room (rooms sorted by stage desc).
  const primaryStageKey = rooms[0]?.stageKey || '';
  const leadStatusKey = contact.properties?.hs_lead_status;

  // Use the stage carried by the lead status itself as the lookup key for
  // card-action-handler resolution.  This ensures that e.g. a DESIGN_INVITED
  // contact whose room is still in "sales" resolves to the designvisit-stage
  // handler rather than falling through to the sales-stage default.
  // Fall back to the room-derived primaryStageKey only when the lead status
  // carries no stage of its own.
  //
  // Stage values in lead_status_config are stored as uppercase+underscore
  // (e.g. 'DESIGN_VISIT', 'SALES') while handler binding stage_key values
  // use lowercase without underscores (e.g. 'designvisit', 'sales').
  // Normalize by lowercasing and stripping underscores.
  const rawActionStage = statusMap.get(leadStatusKey ?? '')?.stage;
  const actionStageKey = rawActionStage
    ? rawActionStage.toLowerCase().replace(/_/g, '')
    : primaryStageKey;

  // Only show a strip when a matching handler is actually configured.
  const handler = cardActionHandlerFor(actionStageKey, leadStatusKey);

  const cahName = handler?.config?.action_name
    ? handler.config.action_name
        .replace(/_/g, ' ')
        .replace(/\b\w/g, (c: string) => c.toUpperCase())
    : '';
  // When there's a draft visit and the handler is start_design_visit, prefer
  // "Continue designing" as the label (unless the admin configured a custom name).
  const isDesignHandler = handler?.type === 'start_design_visit';
  const hasDraft = !!draftVisitId && isDesignHandler;
  const actionLabel = handler
    ? (cahName
        || (hasDraft ? 'Continue designing' : '')
        || (HANDLER_TYPE_LABELS as Record<string, string>)[handler.type]
        || '')
    : resolveActionLabel(actionStageKey, leadStatusKey, undefined);

  const hasNoLeadStatus = !leadStatusKey;
  const { actionTint, actionTextColor } = getActionStripColors({
    hasDraft,
    hasNoLeadStatus,
    handler,
    actionStageKey,
    primaryStageKey,
  });

  const activityTs = latestTimestamp(lastAttempt?.at, contact.properties?.notes_last_contacted);
  const activityCounter = (!dispatchingAction && actionLabel && activityTs)
    ? compactRelativeTime(activityTs, now)
    : null;

  // Unified dispatch: preloads the draft visit when handler is start_design_visit
  // and a draft exists; otherwise dispatches normally.
  const handleActionClick = useCallback(
    async (e: React.MouseEvent) => {
      e.preventDefault();
      e.stopPropagation();
      if (!handler || dispatchingAction) return;
      if (hasDraft && draftVisitId) {
        setDispatchingAction(true);
        try {
          const resp = await fetch(`/api/design-visits/${encodeURIComponent(String(draftVisitId))}`);
          if (!resp.ok) throw new Error('Could not load visit');
          const visit: ExistingVisit = await resp.json();
          openCardActionModal(handler, {
            contactId:    contact.id,
            contactName:  name,
            contactEmail: contact.properties?.email || '',
            contactPhone:  contact.properties?.phone || '',
            contactMobile: contact.properties?.mobilephone || '',
          }, visit);
        } catch {
          // Silent failure — user can navigate to customer detail instead
        } finally {
          setDispatchingAction(false);
        }
      } else {
        dispatchCardActionHandler(handler, {
          contactId:    contact.id,
          contactName:  name,
          contactEmail: contact.properties?.email || '',
          contactPhone:  contact.properties?.phone || '',
          contactMobile: contact.properties?.mobilephone || '',
        });
      }
    },
    [handler, hasDraft, draftVisitId, dispatchingAction, contact, name],
  );

  return (
    <Box
      sx={{
        background: BRAND_COLORS.paper,
        border: `1px solid ${BRAND_COLORS.stone}`,
        borderRadius: `${RADIUS.lg}px`,
        boxShadow: '0 1px 3px rgba(0,0,0,0.06)',
        overflow: 'hidden',
      }}
    >
      {/* Card header */}
      <Box sx={{ p: '12px 14px 10px', borderBottom: `1px solid ${BRAND_COLORS.stone}` }}>
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5, minWidth: 0 }}>
          <UrgencyDot urgency={urgency} />
          <Typography
            sx={{
              fontSize: '0.975rem',
              fontWeight: 700,
              color: BRAND_COLORS.ink1,
              lineHeight: 1.25,
              whiteSpace: 'nowrap',
              overflow: 'hidden',
              textOverflow: 'ellipsis',
              flex: 1,
              minWidth: 0,
            }}
          >
            {name}
          </Typography>
          {canEdit && (
            <IconButton
              size="small"
              aria-label="Edit contact name"
              title="Edit contact"
              onClick={(e) => { e.stopPropagation(); onOpenEdit(contact.id); }}
              sx={{
                flexShrink: 0,
                p: '3px',
                color: BRAND_COLORS.ink4,
                '&:hover': { color: BRAND_COLORS.ink2, background: BRAND_COLORS.stone },
              }}
            >
              <EditIcon sx={{ fontSize: 14 }} />
            </IconButton>
          )}
          {installLabel && (
            <Typography
              sx={{
                fontSize: '0.68rem',
                fontWeight: 600,
                color: BRAND_COLORS.ink3,
                whiteSpace: 'nowrap',
                letterSpacing: '0.01em',
                flexShrink: 0,
              }}
            >
              Install: {installLabel}
            </Typography>
          )}
        </Box>
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mt: '2px', flexWrap: 'wrap' }}>
          <Typography sx={{ fontSize: '0.72rem', fontWeight: 500, color: BRAND_COLORS.ink4, letterSpacing: '0.02em' }}>
            #{contact.id}
          </Typography>
          {contact._statusUnknown && (
            <Box
              component="span"
              title="This contact's HubSpot lead status is missing or not configured in the pipeline. Check HubSpot or the Lead Status admin settings."
              sx={{
                fontSize: '0.62rem',
                fontWeight: 700,
                px: '6px',
                py: '1px',
                borderRadius: '999px',
                background: STATUS_COLORS.warning.bg,
                color: STATUS_COLORS.warning.text,
                border: `1px solid ${STATUS_COLORS.warningActive.bg}`,
                letterSpacing: '0.02em',
                whiteSpace: 'nowrap',
                flexShrink: 0,
              }}
            >
              Unknown status
            </Box>
          )}
          <PhotosReceivedBadge leadStatus={leadStatusKey} />
        </Box>
      </Box>

      {/* Room rows */}
      <Box sx={{ display: 'flex', flexDirection: 'column' }}>
        {rooms.map((room, i) => {
          const colour = stageColour(room.stageKey || '');
          const stageLabel = getStageLabel(room.stageKey || '', workflow);
          const roomLabel = room.room || 'Main';
          const isLast = i === rooms.length - 1;

          return (
            <Box
              key={room.roomIdx}
              onClick={() => onNavigate(contact.id, room.roomIdx)}
              sx={{
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'space-between',
                gap: '10px',
                p: '9px 14px',
                cursor: 'pointer',
                transition: 'background 0.1s',
                WebkitTapHighlightColor: 'transparent',
                borderBottom: isLast ? 'none' : `1px solid ${BRAND_COLORS.stone}`,
                '&:hover': { background: 'rgba(0,0,0,0.03)' },
                '&:active': { background: BRAND_COLORS.stone },
              }}
            >
              <Typography
                sx={{
                  fontSize: '0.85rem',
                  fontWeight: 600,
                  color: BRAND_COLORS.ink2,
                  whiteSpace: 'nowrap',
                  overflow: 'hidden',
                  textOverflow: 'ellipsis',
                  flex: 1,
                  minWidth: 0,
                }}
              >
                {roomLabel}
              </Typography>
              <FitterChip
                room={room}
                platformUsers={platformUsers}
                canAssign={canAssign}
                onOpenPicker={(_cid, _rIdx) => onOpenFitterPicker(contact.id, room.roomIdx)}
              />
              <Box
                component="span"
                sx={{
                  fontSize: '0.72rem',
                  fontWeight: 700,
                  px: '8px',
                  py: '2px',
                  borderRadius: '999px',
                  background: colour.light,
                  color: colour.text,
                  whiteSpace: 'nowrap',
                  flexShrink: 0,
                }}
              >
                {stageLabel}
              </Box>
            </Box>
          );
        })}
      </Box>

      {/* Action strip — always rendered. When a handler is bound to this card's
          stage/lead-status the strip is interactive, shows the action label and
          chevron, and fires the handler on click (start_design_visit with a draft
          doubles as "Continue designing"). When no handler is configured the strip
          renders as a neutral grey placeholder (non-interactive, no label, no
          chevron) so the card layout remains consistent. */}
      <Box
        role={handler ? 'button' : undefined}
        tabIndex={handler ? -1 : undefined}
        title={handler ? (actionLabel || 'Run action') : undefined}
        onClick={handler ? handleActionClick : undefined}
        sx={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          px: '14px',
          py: '9px',
          bgcolor: handler ? actionTint : BRAND_COLORS.stone,
          borderTop: `1px solid ${BRAND_COLORS.stone}`,
          cursor: handler ? (dispatchingAction ? 'wait' : 'pointer') : 'default',
          opacity: dispatchingAction ? 0.7 : 1,
          transition: 'opacity 0.15s, filter 0.12s',
          '&:hover': (handler && !dispatchingAction) ? { filter: 'brightness(0.96)' } : undefined,
        }}
      >
        <Typography sx={{ color: actionTextColor, fontWeight: 600, fontSize: '0.78rem' }}>
          {handler && (dispatchingAction ? 'Opening…' : (
            <>
              {activityCounter && (
                <Tooltip
                  title={buildActivityTooltipContent(lastAttempt ?? null, contact.properties?.notes_last_contacted)}
                  arrow
                  placement="bottom"
                  enterDelay={200}
                >
                  <Box
                    component="span"
                    sx={{ fontWeight: 500, opacity: 0.6, mr: '4px' }}
                  >
                    {activityCounter} ·
                  </Box>
                </Tooltip>
              )}
              {actionLabel}
            </>
          ))}
        </Typography>
        {handler && (dispatchingAction ? (
          <CircularProgress size={12} sx={{ color: actionTextColor }} />
        ) : (
          <ChevronRightIcon sx={{ fontSize: 15, color: actionTextColor, flexShrink: 0 }} />
        ))}
      </Box>

      {/* Activity strip — rendered when a last-attempt record is available.
          Uses formatActivityRow unconditionally (both count>0 and count=0),
          matching the pattern established in CustomersPage. */}
      {lastAttempt?.at && (
        <Tooltip
          title={buildActivityTooltipContent(lastAttempt, contact.properties?.notes_last_contacted)}
          arrow
          placement="top"
          enterDelay={200}
        >
          <Box
            sx={{
              px: 2,
              py: '6px',
              bgcolor: 'grey.50',
              borderTop: '1px solid',
              borderColor: 'divider',
              cursor: 'default',
            }}
          >
            {(() => {
              const { line1, line2 } = formatActivityRow(lastAttempt, relativeTime(lastAttempt.at));
              return (
                <Box sx={{ display: 'flex', flexWrap: 'wrap', alignItems: 'baseline', wordBreak: 'break-word' }}>
                  <Typography variant="caption" color="text.secondary" component="span">
                    {line1}
                  </Typography>
                  <Typography
                    variant="caption"
                    color="text.secondary"
                    component="span"
                    sx={{ '@media (max-width: 359px)': { display: 'none' } }}
                  >
                    &nbsp;·&nbsp;
                  </Typography>
                  <Typography
                    variant="caption"
                    color="text.secondary"
                    component="span"
                    sx={{ '@media (max-width: 359px)': { flexBasis: '100%' } }}
                  >
                    {line2}
                  </Typography>
                </Box>
              );
            })()}
          </Box>
        </Tooltip>
      )}

      {/* Task badge */}
      {!!openTaskCount && (
        <Box sx={{ px: '14px', py: '8px', borderTop: `1px solid ${BRAND_COLORS.stone}`, display: 'flex', alignItems: 'center', gap: 1, flexWrap: 'wrap' }}>
          <TasksBadge contactId={contact.id} openTaskCount={openTaskCount} />
        </Box>
      )}

      {/* Invoice badge */}
      <InvoiceBadge contact={contact} qb={qb} onOpen={onOpenInvoice} />
    </Box>
  );
}

